(60, 'en', 'proposal_email', 'New Proposal', '<p>Proposal <strong>{PROPOSAL_REF}</strong></p> <p>Hi <strong>{CLIENT}</strong></p> <p>Thanks for your business inquiry.</p> <p>The Proposal <strong>{PROPOSAL_REF} </strong>is attached with this email.<br /> Proposal&nbsp;Overview:<br /> Proposal&nbsp;# :<strong> {PROPOSAL_REF}</strong><br /> Amount: <strong>{CURRENCY} {AMOUNT}</strong><br /> <br /> You can view the estimate online at:<br /> <big><strong><a href=\"{PROPOSAL_LINK}\">View Proposal</a></strong></big><br /> <br /> Best Regards,<br /> The <strong>{SITE_NAME}</strong> Team</p> '),
(61, 'en', 'project_overdue_email', 'Project Overdue Notice', '<p>Project Overdue</p>\r\n\r\n<p><strong>Hello {CLIENT}</strong></p>\r\n\r\n<p>This is the notice that your project overdue.&nbsp;<br />\r\n<br />\r\nProject name : <strong>{PROJECT_NAME}</strong><br />\r\nDue date : <strong>{DUE_DATE}</strong><br />\r\nYou can login to see the status of your project by using this link:<br />\r\n<big><a href=\"{PROJECT_LINK}\"><strong>View Project</strong></a></big></p>\r\n\r\n<p><br />\r\nBest Regards<br />\r\nThe {SITE_NAME} Team</p>\r\n\r\n<p>&nbsp;</p>\r\n'),
(62, 'en', 'estimate_overdue_email', 'Estimate Overdue Notice', '                                <p>Estimate {ESTIMATE_REF}</p>\r\n\r\n<p>Hi {CLIENT}</p>\r\n\r\n<p>This is the notice that your Estimate┬áoverdue.┬á├âãÆ├åÔÇÖ├âÔÇÜ├é┬ó├âãÆ├é┬ó├â┬ó├óÔÇÜ┬¼├à┬í├âÔÇÜ├é┬¼├âãÆ├é┬ó├â┬ó├óÔé¼┼í├é┬¼├âÔÇÜ├é┬╣<br>\r\n<br>\r\nEstimate Overview:<br>\r\nEstimate # : {ESTIMATE_REF}<br>\r\nDue Date: {DUE_DATE}<br>\r\nAmount: {CURRENCY} {AMOUNT}<br>\r\n<br>\r\nYou can view the estimate online at:<br>\r\n<big><strong><a href=\"{ESTIMATE_LINK}\">View Estimate</a></strong></big><br>\r\n<br>\r\nBest Regards,<br>\r\nThe {SITE_NAME} Team</p>\r\n'),
(63, 'en', 'proposal_overdue_email', 'New Estimate', '<p>Proposal&nbsp;<strong>{PROPOSAL_REF}</strong></p>\r\n\r\n<p>Hi&nbsp;<strong>{CLIENT}</strong></p>\r\n\r\n<p>This is the notice that your Proposal&nbsp;overdue.&nbsp;<br />\r\n<br />\r\nProposal&nbsp;Overview:<br />\r\nProposal&nbsp;# :<strong>&nbsp;{PROPOSAL_REF}</strong><br />\r\nDue Date: <strong>{DUE_DATE}</strong>├âãÆ├åÔÇÖ├âÔÇÜ├é┬ó├âãÆ├é┬ó├â┬ó├óÔÇÜ┬¼├à┬í├âÔÇÜ├é┬¼├âãÆ├é┬ó├â┬ó├óÔé¼┼í├é┬¼├âÔÇÜ├é┬╣<br />\r\nAmount:&nbsp;<strong>{CURRENCY} {AMOUNT}</strong><br />\r\n<br />\r\nYou can view the estimate online at:<br />\r\n<big><strong><a href=\"{PROPOSAL_LINK}\">View Proposal</a></strong></big><br />\r\n<br />\r\nBest Regards,<br />\r\nThe&nbsp;<strong>{SITE_NAME}</strong>&nbsp;Team</p>\r\n'),
(64, 'en', 'call_for_interview', 'You have an interview offer!!!', '<p>Hello&nbsp;<strong>{NAME}</strong>,</p>\n\n<p>You have an interview offer for you.please see the details.&nbsp;<br />\n<br />\n<strong>Job Summary</strong>:<br />\nJob Title # :<strong>&nbsp;{JOB_TITLE}</strong><br />\nDesignation # :<strong>&nbsp;{DESIGNATION}</strong><br />\nInterview Date: <strong>{DATE}</strong></p>\n\n<p><strong>Office Address</strong><br />\nAH.Tower (5th Floor), Alokar More<br />\nGhoramara, Boalia, Rajshahi<br />\nBangladesh &ndash;&nbsp;<a href=\"https://maps.app.goo.gl/pRie4zYQdhkxuB4U7\" target=\"_blank\">Map</a></p>\n\n<p><br />\nYou can view the circular details online at:<br />\n<big><strong><a href=\"{LINK}\">View Job Circular</a></strong></big><br />\n<br />\nBest Regards,<br />\nThe&nbsp;<strong>{SITE_NAME}</strong>&nbsp;Team</p>\n'),
(65, 'en', 'ticket_reopened_email', 'Ticket [SUBJECT] reopened', '<p>Ticket re-opened</p>\r\n\r\n<p>Hi {RECIPIENT},</p>\r\n\r\n<p>Ticket&nbsp;<strong>{SUBJECT}</strong>&nbsp;was re-opened by&nbsp;<strong>{USER}</strong>.<br />\r\nStatus :&nbsp;Open<br />\r\nClick on the below link to see the ticket details and post replies:&nbsp;<br />\r\n<a href=\"{TICKET_LINK}\"><strong>View Ticket</strong></a><br />\r\n<br />\r\n<br />\r\nBest Regards,<br />\r\n{SITE_NAME}</p>\r\n'),
(66, 'en', 'deposit_email', 'A deposit have been Received', '<p>Hi there,</p> <p>The&nbsp;<strong>{NAME}</strong>&nbsp;of deposit&nbsp;<strong>{AMOUNT}&nbsp;</strong>has been Deposit into <strong>{ACCOUNT}</strong> the new balance is <strong>{BALANCE}</strong></p> <p>You can view this deposit by logging in to the portal using the link below.<br /> <br /> <big><strong><a href=\"{URL}\">View Deposit</a></strong></big><br /> <br /> <br /> Regards,<br /> <br /> The&nbsp;<strong>{SITE_NAME}</strong>&nbsp;Team</p>'),
(67, 'en', 'clock_in_email', 'The {NAME} Just clock in', '<p>Hi there,</p>\r\n\r\n<p>The├âÔÇÜ├é┬á<strong>{NAME}</strong> just├âÔÇÜ├é┬áClock In by using The IP. The IP is:├âÔÇÜ├é┬á<strong>{IP}</strong> and the time is: ├âÔÇÜ├é┬á<strong>{TIME}</strong><strong> </strong></p>\r\n\r\n<p>You can view this attendance by logging in to the portal using the link below.<br>\r\n<br>\r\n<big><strong><a href=\"{URL}\">View Details</a></strong></big><br>\r\n<br>\r\n<br>\r\nRegards,<br>\r\n<br>\r\nThe├âÔÇÜ├é┬á<strong>{SITE_NAME}</strong>├âÔÇÜ├é┬áTeam</p>\r\n'),
(68, 'en', 'trying_clock_email', 'The {NAME} Trying to clock', '<p>Hi there,</p>\r\n\r\n<p>The├âÔÇÜ├é┬á<strong>{NAME} </strong> Trying to clock├âÔÇÜ├é┬áin by Unknown IP.The IP is: <strong>{IP}</strong> and the time is: <strong>{TIME}</strong></p>\r\n\r\n<p>You can view this IP by logging in to the portal using the link below.<br>\r\n<br>\r\n<big><strong><a href=\"{URL}\">View Details</a></strong></big><br>\r\n<br>\r\n<br>\r\nRegards,<br>\r\n<br>\r\nThe├âÔÇÜ├é┬á<strong>{SITE_NAME}</strong>├âÔÇÜ├é┬áTeam</p>\r\n'),
(69, 'en', 'clock_out_email', 'The {NAME} Just clock Out', '<p>Hi there,</p>\r\n\r\n<p>The├âÔÇÜ├é┬á<strong>{NAME}</strong>├âÔÇÜ├é┬ájust├âÔÇÜ├é┬áClock Out by using The IP. The IP is:├âÔÇÜ├é┬á<strong>{IP}</strong>├âÔÇÜ├é┬áand the time is: ├âÔÇÜ├é┬á<strong>{TIME}</strong></p>\r\n\r\n<p>You can view this attendance by logging in to the portal using the link below.<br>\r\n<br>\r\n<big><strong><a href=\"{URL}\">View Details</a></strong></big><br>\r\n<br>\r\n<br>\r\nRegards,<br>\r\n<br>\r\nThe├âÔÇÜ├é┬á<strong>{SITE_NAME}</strong>├âÔÇÜ├é┬áTeam</p>\r\n'),
(70, 'en', 'invoice_item_refund_request', 'A new Refunded request recived for Invoice {REF}', '<p><strong>Hello </strong><br> <br> A new item refunded request received for Invoice {REF}.<br> <br> You can view the invoice online at:<br> <big><strong><a href=\"{LINK}\">View Refund Stock </a></strong></big><br> <br> Best Regards<br> <br> The {SITE_NAME} Team</p> '),
(71, 'en', 'credit_note_email', 'New Credit Note', '<p>Credit Note {credit_note_REF}</p>\r\n\r\n<p>Hi {CLIENT}</p>\r\n\r\n<p>Thanks for your business inquiry.</p>\r\n\r\n<p>The Credit Note {credit_note_REF} is attached with this email.<br />\r\nCredit Note Overview:<br />\r\nCredit Note # : {credit_note_REF}<br />\r\nAmount: {CURRENCY} {AMOUNT}<br />\r\n<br />\r\nYou can view the Credit Note online at:<br />\r\n<big><strong><a href=\"{credit_note_LINK}\">View Credit Note</a></strong></big><br />\r\n<br />\r\nBest Regards,<br />\r\nThe {SITE_NAME} Team</p>\r\n'),
(72, 'en', 'meeting_start', 'Your Meeting start now.we are waiting', ' <p>Hello {USER}!</p>\r\n\r\n\r\n<p>A Meeting start from {HOST}.you are invited.</p>\r\n\r\n\r\n<p>we are waiting for you:<br>\r\n</p><p> Click on link to join the meeting:<br>\r\n<big><strong><a href=\"{MEETING_URL}\">join the meeting...</a></strong></big><br>\r\nLink doesn\'t work? Copy the following link to your browser address bar:<br>\r\n<a href=\"{MEETING_URL}\">{MEETING_URL}</a></p>\r\n\r\n\r\n<p><br>\r\n<br>\r\nHave fun!<br>\r\nThe {SITE_NAME} Team</p>'),
(73, 'en', 'meeting_start', 'Your Meeting start now.we are waiting', ' <p>Hello {USER}!</p>\r\n\r\n\r\n<p>A Meeting start from {HOST}.you are invited.</p>\r\n\r\n\r\n<p>we are waiting for you:<br>\r\n</p><p> Click on link to join the meeting:<br>\r\n<big><strong><a href=\"{MEETING_URL}\">join the meeting...</a></strong></big><br>\r\nLink doesn\'t work? Copy the following link to your browser address bar:<br>\r\n<a href=\"{MEETING_URL}\">{MEETING_URL}</a></p>\r\n\r\n\r\n<p><br>\r\n<br>\r\nHave fun!<br>\r\nThe {SITE_NAME} Team</p>');
