INSERT INTO `tbl_holiday` (`holiday_id`, `event_name`, `description`, `start_date`, `end_date`, `location`, `color`) VALUES
(1, 'Durga Puja(Bijoya Dashami 2024)', 'Holiday Notice for Durga Puja\n\nThis is to inform all employees that TIC Limited will remain closed on 13th October 2024 in observance of Bijoya Dashami during the Durga Puja festival.\n\nNormal operations will resume on the following working day. We wish everyone a joyful and safe celebration.\n\nThank you.\n\nBest regards,\nForid Mondol\nManaging Director\nTIC Limited', '2024-10-13', '2024-10-13', 'Rajshahi Bangladesh', '#83c340'),
(2, 'Holiday Notice government has declared Thursday, October 10, 2024, as a public holiday in observance of Durga Puja', 'Dear Team,\n\nPlease be informed that the government has declared Thursday, October 10, 2024, as a public holiday in observance of Durga Puja, one of the most significant Hindu festivals. As such, TIC Limited will remain closed on this date.\n\nWe encourage all staff to take this time to relax and recharge. Regular operations will resume on Saturday, October 12, 2024.\n\nThank you for your attention, and we wish you all a happy and restful holiday.\n\nBest regards,\nForid Mondol\nTIC Limited', '2024-10-10', '2024-10-10', '', '#83c340');
