INSERT INTO `tbl_job_appliactions` (`job_appliactions_id`, `job_circular_id`, `name`, `email`, `mobile`, `cover_letter`, `resume`, `application_status`, `apply_date`, `send_email`, `interview_date`) VALUES
(7, 7, 'Abu Torab ', 'maxarnobtorab@gmail.com', '01797731522', '<p xss=removed>Dear┬á HR,</p><p xss=removed>I hope this message finds you well. I am writing to express my interest in the Web Development Internship position at TIC Limited, as advertised. With a strong passion for web development and a solid foundation in HTML, CSS, JavaScript, and React, I am eager to contribute to your team and further develop my skills in a professional environment.</p><p xss=removed>I am particularly drawn to the opportunity at TIC Limited because of your focus on real-world projects, mentorship, and the potential to grow within the company. I believe that my technical skills, enthusiasm for learning, and commitment to delivering high-quality work make me a great fit for this role.</p><p xss=removed>┬á Below are some of the projects I\'ve worked on, available on my GitHub:</p><p xss=removed>1.<a href=\"https://torabarnob203311003.github.io/BURGER-SHOP/\" target=\"_blank\" rel=\"noreferrer\" xss=removed>BURGER-SHOP (torabarnob203311003.github.io)</a></p><p xss=removed>2.<a href=\"https://torabarnob203311003.github.io/E-organic/\" target=\"_blank\" rel=\"noreferrer\" xss=removed>Organic - (torabarnob203311003.github.io)</a></p><p xss=removed>3.┬á┬á<a href=\"https://torabarnob203311003.github.io/Penguin-Fashion/\" target=\"_blank\" rel=\"noreferrer\" xss=removed>Penguin-Fashion (torabarnob203311003.github.io)</a></p><p xss=removed>I have attached my resume for your review and would love the chance to discuss how I can contribute to your team. Thank you for considering my application. I look forward to the possibility of working with TIC Limited and being part of your dynamic and supportive team.</p><p xss=removed>Best regards,<br>Abu Torab</p>', 'uploads/Abu_Torab_intern.pdf', 0, '2024-10-01 04:04:12', NULL, NULL),
(8, 7, 'Md. Abdullah Al Kafi', 'kaficsmy9@gmail.com', '01878403262', '<p><a href=\"https://ticlimited.com.bd:2096/cpsess0197536187/3rdparty/roundcube/?_task=mail&_frame=1&_mbox=INBOX&_uid=115&_part=3&_action=get&_extwin=1\" target=\"_blank\">Cover letter</a><br></p>', 'uploads/Md__Abdullah_Al_Kafi.pdf', 0, '2024-10-01 04:09:49', NULL, NULL),
(9, 7, 'MD IBRHAIM', 'shunibrahim@gmail.com', '01701013390', '<span xss=removed>I recently got to know that your company is hiring interns. I am willing to apply for an internship in your company. I am a web developer. I have worked as a wordpress┬ádeveloper for almost 1.5 years for a company. I have learnt HTML, CSS, JavaScript and for Backend I have learnt PHP and MySQL. I am currently learning ReactJS and MongoDB I have completed lessons of ReactJS and MongoDB but I haven\'t build any project using ReactJS and MongoDB but I have created some small projects using HTML, CSS, JS, PHP and MySQL. Therefore I expect that you would be kind enough┬áto contact me for further information about this and if you want any more details please let me know through email. Thank You.</span>', 'uploads/Ibrhaim_Resume_INT.pdf', 0, '2024-10-01 04:10:58', NULL, NULL),
(10, 7, 'MD SHAHORIAR HOSSAIN SHOJIB', 'shojib.shojib10@gmail.com', '01719573754', '<p xss=removed>Dear┬á<span xss=removed>HR</span>,</p><p xss=removed>I am writing to express my interest in the┬á┬á<span xss=removed>Web Development Intern</span>┬á┬á┬áposition at TIC LTD. As a versatile web and Android app developer with expertise in Kotlin, HTML, CSS, and PHP,Python, I am eager to contribute to your team with my strong technical skills and passion for creating robust applications.</p><p xss=removed>I have a solid background in back-end development using Django, along with experience in working with databases such as PostgreSQL, MySQL, and SQL Server.┬á</p><p xss=removed>You can view my work on my GitHub profile:┬á<a href=\"https://github.com/shojib353\" target=\"_blank\" rel=\"noreferrer\" xss=removed>https://github.com/shojib353</a>.</p><p xss=removed>Please find my CV attached for further details about my qualifications. Thank you for considering my application.┬á┬á<br></p><p xss=removed><br></p><p xss=removed>Thank you for considering my application. I look forward to the opportunity to discuss how my skills and passion can benefit TIC LTD┬á .</p><p xss=removed>Warm regards,</p><p xss=removed>MD SHAHORIAR HOSSAIN SHOJIB</p>', 'uploads/SHOJIB_Resume.pdf', 0, '2024-10-01 04:12:26', NULL, NULL),
(11, 7, 'Nagib Mahfuze Akib', 'n.mahfuze@gmail.com', '01738139909', '<p class=\"v1MsoNormal\" xss=removed><span xss=removed>Respected Hiring Manager,</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>I\'m writing to TIC Limited to express interest in the Frontend Web Design Intern position. I\'m a driven and enthusiastic person with a background in computer science and engineering, and I\'m thrilled about the chance to be a part of your vibrant team and work on actual web design projects.</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>┬á</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>I have honed my skills in HTML, CSS, and a variety of front-end frameworks during my academic career. I\'ve successfully finished a number of projects involving the development of user-friendly, responsive interfaces. My attention to detail and comprehension of user experiences concepts guarantee that the websites I create have smooth functioning in addition to attractive visual design.</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>┬á</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>My main excitement regarding the opportunity at TIC Limited is the prospect of working with seasoned professionals and developing my abilities in a cooperative team setting. My career aspirations are well aligned with the mentorship and practical experience your internship provides. I\'m really excited to contribute to initiatives that push the limits of innovative web design.</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>┬á</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>With my passion, technical expertise, and eagerness to learn, I\'m sure I\'ll be a great addition to your team. I am excited to take on new tasks and am very versatile. Depending on how well I perform, I hope to be hired on a permanent basis at TIC Limited.</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>┬á</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>┬á</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>I appreciate your consideration of my application. I\'m eager to talk about how TIC Limited will benefit from my experience, abilities, and certifications. I can be reached at┬á<span xss=removed>01738139909┬á</span>or by email at┬á<span xss=removed>n.mahfuze@gmail.</span>com and am available for an interview as soon as it is convenient for you.</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed><br></span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>Sincerely,</span></p><p class=\"v1MsoNormal\" xss=removed><span xss=removed>Nagib Mahfuze Akib</span></p>', 'uploads/Resume-of-Nagib_Mahfuze.pdf', 0, '2024-10-01 04:14:12', NULL, NULL),
(12, 7, 'Masrur Rahman', 'masrur.mmrs@gmail.com', '01719237487', '<p xss=removed><span xss=removed>Dear HR,</span></p><p xss=removed>Assalamualaikum. I hope you are doing well. My name is Masrur, and I\'m a first-year Computer Science student at Varendra University. I\'m writing to express my interest in the Web Development Intern position at TIC Limited, as advertised.</p><p xss=removed>I am passionate about web development and have been honing my skills in HTML, CSS, JavaScript (ES6), Typescript, React, Next, Express, and NodeJS. I am excited to work with a dynamic and supportive team, gain hands-on experience, and contribute to real-world projects.</p><p xss=removed>I\'ve attached my resume and cover letter for you to look over. I would be grateful for the opportunity to discuss how I can contribute to your team and learn from your professionals.</p><p xss=removed>Thank you for considering my application. I\'m looking forward to working at TIC Limited.</p><p xss=removed><span xss=removed>Best regards,</span><br>Masrur Rahman<br>+8801719237487<br><a href=\"https://www.linkedin.com/in/masrur-mmrs\" target=\"_blank\" rel=\"noreferrer\" xss=removed>LinkedIn</a><br><a href=\"https://github.com/masrur-mmrs\" target=\"_blank\" rel=\"noreferrer\" xss=removed>Github</a></p>', 'uploads/MashrurWebDev_Internship_Resume.pdf', 0, '2024-10-01 04:16:05', NULL, NULL),
