(50, 7, 'Nasif Kabir', 'nasifjubian37@gmail.com', '8801745217166', '<p xss=removed><span xss=removed>Dear Sir,</span></p><p xss=removed>I am writing to express my interest in the Frontend Web Design internship position at TIC Limited, as advertised. I recently graduated from Varendra University with a degree in Computer Science and Engineering, and I am excited about the opportunity to contribute to your team while further developing my skills in web development and design.</p><p xss=removed>Throughout my academic journey, I have gained a strong foundation in HTML, CSS, Tailwind CSS & JavaScript. I have worked on several projects, including Easy Bus Paribahan┬áTicket Website, Alphabet Clash Game etc. These experiences have fueled my passion for web development, and I am eager to take on real-world challenges as part of your dynamic team.</p><p xss=removed>Thank you for considering my application. I am excited about the prospect of joining TIC Limited and would love the opportunity to discuss my qualifications further. I have attached my resume for your review.</p><p xss=removed>I look forward to hearing from you.</p><p xss=removed><span xss=removed>Sincerely,<br>Nasif Kabir</span></p>', 'uploads/NASIF_KABIR_RESUME.pdf', 0, '2024-10-09 08:29:26', NULL, NULL),
(51, 7, 'Nasif Kabir', 'nasifjubian37@gmail.com', '8801745217166', '<p xss=removed><span xss=removed>Dear Sir,</span></p><p xss=removed>I am writing to express my interest in the Frontend Web Design internship position at TIC Limited, as advertised. I recently graduated from Varendra University with a degree in Computer Science and Engineering, and I am excited about the opportunity to contribute to your team while further developing my skills in web development and design.</p><p xss=removed>Throughout my academic journey, I have gained a strong foundation in HTML, CSS, Tailwind CSS & JavaScript. I have worked on several projects, including Easy Bus Paribahan┬áTicket Website, Alphabet Clash Game etc. These experiences have fueled my passion for web development, and I am eager to take on real-world challenges as part of your dynamic team.</p><p xss=removed>Thank you for considering my application. I am excited about the prospect of joining TIC Limited and would love the opportunity to discuss my qualifications further. I have attached my resume for your review.</p><p xss=removed>I look forward to hearing from you.</p><p xss=removed><span xss=removed>Sincerely,<br>Nasif Kabir</span></p>', 'uploads/NASIF_KABIR_RESUME.pdf', 0, '2024-10-09 08:29:47', NULL, NULL);
INSERT INTO `tbl_job_circular` (`job_circular_id`, `job_title`, `designations_id`, `vacancy_no`, `posted_date`, `employment_type`, `experience`, `age`, `salary_range`, `last_date`, `description`, `status`, `created_date`, `permission`) VALUES
(1, 'Business Relationship Officer', 2, '3', '2024-09-28', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-09-30', '<p xss=removed>TIC Limited is a leader in IT solutions, offering cutting-edge services to clients across various industries. We are focused on building long-term relationships with our clients by delivering customized and impactful solutions. We are currently seeking a Business Relationship Officer to join our team and help strengthen and expand our client partnerships.</p><p xss=removed><span xss=removed>Position Overview:</span></p><p xss=removed>The Business Relationship Officer will be responsible for managing and nurturing relationships with existing and potential clients. You will act as the primary point of contact for key accounts, ensuring customer satisfaction, and identifying opportunities for further business development. This role is ideal for someone with strong interpersonal skills and a deep understanding of client needs within the IT industry.</p><p xss=removed><span xss=removed>Key Responsibilities:</span></p><ul xss=removed><li xss=removed>Build and maintain strong relationships with clients, understanding their needs and ensuring satisfaction</li><li xss=removed>Act as the key liaison between the client and internal teams, ensuring that services are delivered according to the clientÔÇÖs expectations</li><li xss=removed>Identify and pursue new business opportunities within existing client accounts</li><li xss=removed>Develop and implement strategies to enhance client engagement and retention</li><li xss=removed>Coordinate with the sales and technical teams to provide tailored solutions for clients</li><li xss=removed>Prepare regular reports on client feedback, business performance, and opportunities for improvement</li><li xss=removed>Participate in client meetings, presentations, and negotiations as required</li><li xss=removed>Keep up to date with industry trends, market conditions, and competitor activities to provide strategic insights</li></ul><p xss=removed><span xss=removed>Requirements:</span></p><ul xss=removed><li xss=removed>BachelorÔÇÖs degree in Business, Marketing, or related field</li><li xss=removed>Proven experience in client relationship management or business development</li><li xss=removed>Strong communication and negotiation skills</li><li xss=removed>Ability to work independently and collaboratively with cross-functional teams</li><li xss=removed>Excellent problem-solving skills and attention to detail</li><li xss=removed>Knowledge of the IT industry is preferred</li><li xss=removed>Ability to manage multiple accounts and prioritize tasks effectively</li></ul><p xss=removed><span xss=removed>What We Offer:</span></p><ul xss=removed><li xss=removed>Competitive salary and benefits</li><li xss=removed>Opportunities for career growth and professional development</li><li xss=removed>Supportive and collaborative work environment</li><li xss=removed>Health and wellness programs</li></ul>', 'published', '2024-09-28 11:45:44', 'all'),
(2, 'Facebook Ads Expert', 2, '2', '2024-09-30', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-29', '<p xss=removed>TIC Limited is a forward-thinking IT solutions provider that specializes in delivering innovative products and services to a wide range of clients. As part of our digital marketing expansion, we are seeking a skilled and experienced Facebook Ads Expert to drive our paid advertising strategy on the Facebook platform and help scale our business growth.</p><p xss=removed><span xss=removed>Position Overview:</span></p><p xss=removed>We are looking for a Facebook Ads Expert who will be responsible for creating, managing, and optimizing Facebook advertising campaigns. The ideal candidate will have deep expertise in Facebook Ads Manager, targeting strategies, and data-driven decision-making. You will work closely with the marketing team to generate leads, increase brand awareness, and maximize return on investment (ROI) from Facebook advertising.</p><p xss=removed><span xss=removed>Key Responsibilities:</span></p><ul xss=removed><li xss=removed>Develop, launch, and manage paid advertising campaigns on Facebook and Instagram</li><li xss=removed>Conduct thorough audience research and utilize FacebookÔÇÖs targeting tools to reach the right demographics</li><li xss=removed>Create compelling ad copy and visually engaging creatives to capture user attention</li><li xss=removed>Monitor and analyze campaign performance metrics (CTR, CPC, CPA, ROAS) and optimize campaigns for maximum effectiveness</li><li xss=removed>A/B test different creatives, audiences, and bidding strategies to improve ad performance</li><li xss=removed>Stay updated with FacebookÔÇÖs algorithm changes, ad policies, and best practices</li><li xss=removed>Collaborate with the design and content teams to ensure ad creatives align with marketing goals</li><li xss=removed>Provide detailed reports and insights on campaign performance, including actionable recommendations for improvements</li></ul><p xss=removed><span xss=removed>Requirements:</span></p><ul xss=removed><li xss=removed>Proven experience in managing Facebook Ads campaigns with a strong track record of success</li><li xss=removed>Proficiency in Facebook Ads Manager and related tools</li><li xss=removed>Ability to analyze data and make data-driven decisions to optimize campaign performance</li><li xss=removed>Strong knowledge of audience segmentation, retargeting, and pixel implementation</li><li xss=removed>Experience with A/B testing and creative optimization</li><li xss=removed>Excellent written and verbal communication skills</li><li xss=removed>Familiarity with budget management and scaling campaigns</li><li xss=removed>BachelorÔÇÖs degree in Marketing, Advertising, or related field is preferred</li></ul><p xss=removed><span xss=removed>What We Offer:</span></p><ul xss=removed><li xss=removed>Competitive salary and performance-based incentives</li><li xss=removed>Professional development opportunities</li><li xss=removed>Flexible work arrangements (remote or hybrid options available)</li><li xss=removed>Health and wellness benefits</li><li xss=removed>Collaborative work environment with a strong focus on innovation</li></ul><p xss=removed><br xss=removed></p>', 'published', '2024-09-30 06:00:26', 'all'),
(3, 'Social Media Marketer', 2, '5', '2024-09-30', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-30', '<p xss=removed>TIC Limited is an industry leader in IT solutions, providing innovative products and services that help our clients achieve success. We are looking for a dynamic and creative Social Media Marketer to elevate our online presence across various social platforms, including Reddit, Quora, Facebook, Tumblr, and Pinterest.</p><p xss=removed><span xss=removed>Position Overview:</span></p><p xss=removed>As a Social Media Marketer at TIC Limited, you will be responsible for planning, creating, and managing marketing campaigns across multiple social platforms. Your goal will be to increase brand awareness, generate leads, and engage our target audience on platforms such as Reddit, Quora, Facebook, Tumblr, and Pinterest, along with other social channels. YouÔÇÖll have a strong understanding of how each platform works, including best practices for engaging users on each network.</p><p xss=removed><span xss=removed>Key Responsibilities:</span></p><ul xss=removed><li xss=removed><span xss=removed>Reddit Marketing:</span>┬áEngage with relevant communities, participate in discussions, and promote TIC LimitedÔÇÖs services while adhering to RedditÔÇÖs unique culture and rules.</li><li xss=removed><span xss=removed>Quora Marketing:</span>┬áProvide value by answering questions related to TIC LimitedÔÇÖs industry, establish brand authority, and drive traffic through insightful content.</li><li xss=removed><span xss=removed>Facebook Marketing:</span>┬áManage Facebook pages and groups, create engaging content, run targeted ads, and interact with followers to build brand loyalty.</li><li xss=removed><span xss=removed>Tumblr Marketing:</span>┬áCreate and share visual and text-based content that appeals to TumblrÔÇÖs creative and niche audiences.</li><li xss=removed><span xss=removed>Pinterest Marketing:</span>┬áDevelop visually appealing boards that showcase TIC LimitedÔÇÖs services, and use SEO best practices to drive traffic from Pinterest.</li><li xss=removed><span xss=removed>Content Creation:</span>┬áDesign creative content (text, images, videos) for various platforms tailored to each platformÔÇÖs audience and trends.</li><li xss=removed><span xss=removed>Analytics and Optimization:</span>┬áTrack performance metrics (engagement, traffic, conversions) across platforms and optimize strategies to improve results.</li><li xss=removed><span xss=removed>Collaborate with Marketing Team:</span>┬áWork closely with the broader marketing team to align social media strategies with overall company objectives.</li></ul><p xss=removed><span xss=removed>Requirements:</span></p><ul xss=removed><li xss=removed>Proven experience in managing social media platforms, especially Reddit, Quora, Facebook, Tumblr, and Pinterest</li><li xss=removed>Strong understanding of platform-specific strategies and best practices</li><li xss=removed>Creativity in content creation (copywriting, graphic design, or video production skills are a plus)</li><li xss=removed>Ability to analyze and report on social media performance metrics</li><li xss=removed>Excellent written and verbal communication skills</li><li xss=removed>Up-to-date with the latest trends in social media and digital marketing</li><li xss=removed>BachelorÔÇÖs degree in Marketing, Communications, or related field preferred</li></ul><p xss=removed><span xss=removed>What We Offer:</span></p><ul xss=removed><li xss=removed>Competitive salary and benefits package</li><li xss=removed>Opportunities for career growth and development</li><li xss=removed>Flexible working options (remote or hybrid)</li><li xss=removed>Health and wellness programs</li><li xss=removed>Collaborative and innovative work environment</li></ul><p xss=removed><br xss=removed></p>', 'published', '2024-09-30 06:01:24', 'all'),
(4, 'Digital Marketing Expert', 2, '5', '2024-09-30', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-30', '<p xss=removed>TIC Limited is a dynamic and growing company, specializing in providing top-tier IT solutions and services. We are passionate about innovation and committed to delivering exceptional products and customer service. As we expand our team, we are looking for driven professionals who thrive in a fast-paced environment and are eager to contribute to our success.</p><p xss=removed><span xss=removed>Position Overview:</span></p><p xss=removed>We are seeking a [Job Title] to join our team. In this role, you will be responsible for [briefly describe the key responsibilities and the impact of the position]. The ideal candidate will have [years of experience or expertise] in [relevant field] and will bring a positive attitude, a passion for technology, and a commitment to excellence.</p><p xss=removed><span xss=removed>Key Responsibilities:</span></p><ul xss=removed><li xss=removed>[List core duties]</li><li xss=removed>Collaborate with cross-functional teams to [insert specific tasks]</li><li xss=removed>Support in maintaining and enhancing [specific systems, platforms, or processes]</li><li xss=removed>Identify and troubleshoot issues related to [relevant area]</li><li xss=removed>Stay updated on industry trends and best practices to contribute to continuous improvement efforts</li></ul><p xss=removed><span xss=removed>Requirements:</span></p><ul xss=removed><li xss=removed>BachelorÔÇÖs degree in [relevant field] or equivalent experience</li><li xss=removed>[X years] of experience in [field/industry]</li><li xss=removed>Strong proficiency in [specific skills, tools, or languages]</li><li xss=removed>Excellent communication and teamwork skills</li><li xss=removed>Ability to manage multiple tasks and meet deadlines</li></ul><p xss=removed><span xss=removed>What We Offer:</span></p><ul xss=removed><li xss=removed>Competitive salary</li><li xss=removed>Professional growth opportunities</li><li xss=removed>Friendly and collaborative work environment</li><li xss=removed>Health and wellness benefits</li><li xss=removed>Opportunities for continuous learning and development</li></ul>', 'published', '2024-09-30 06:02:28', 'all'),
(5, 'Sales & Marketing Executive', 2, '5', '2024-09-30', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-30', '<h3 xss=removed><span xss=removed>Job Description:</span></h3><p xss=removed>We are looking for a motivated┬á<span xss=removed>Sales & Marketing Executive</span>┬áto join our team at┬á<span xss=removed>TIC Limited</span>. The role involves developing and executing sales strategies, building strong relationships with clients, and driving marketing campaigns to increase brand visibility. The ideal candidate will be energetic, goal-oriented, and passionate about achieving sales targets.</p><h3 xss=removed><span xss=removed>Job Responsibilities:</span></h3><ul xss=removed><li xss=removed>Develop and implement sales strategies to meet company goals.</li><li xss=removed>Identify potential clients and generate new business opportunities.</li><li xss=removed>Build and maintain strong relationships with existing clients.</li><li xss=removed>Plan and execute marketing campaigns, both online and offline.</li><li xss=removed>Conduct market research to identify trends and opportunities.</li><li xss=removed>Collaborate with internal teams to align marketing strategies with business objectives.</li><li xss=removed>Prepare and present sales and marketing reports to management.</li></ul><h3 xss=removed><span xss=removed>Required Skills:</span></h3><ul xss=removed><li xss=removed>Strong communication and interpersonal skills.</li><li xss=removed>Proven ability to achieve sales targets and handle customer relationships.</li><li xss=removed>Familiarity with digital marketing tools and platforms.</li><li xss=removed>Ability to work independently and in a team environment.</li><li xss=removed>Proficiency in Microsoft Office (Word, Excel, PowerPoint).</li></ul><h3 xss=removed><span xss=removed>Additional Skills (Optional):</span></h3><ul xss=removed><li xss=removed>Experience with social media marketing and SEO.</li><li xss=removed>Knowledge of CRM software.</li></ul><h3 xss=removed><span xss=removed>Benefits:</span></h3><ul xss=removed><li xss=removed>Competitive salary.</li><li xss=removed>Incentives based on performance.</li><li xss=removed>Friendly and collaborative work environment.</li><li xss=removed>Opportunities for professional growth and development.</li></ul>', 'published', '2024-09-30 06:03:16', 'all'),
(6, 'Flutter Developer', 4, '1', '2024-09-30', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-30', '<h3 xss=removed><span xss=removed>Job Responsibilities:</span></h3><ul xss=removed><li xss=removed>Develop and maintain high-performance mobile applications using Flutter for Android and iOS platforms.</li><li xss=removed>Collaborate with UI/UX designers to implement attractive and user-friendly interfaces.</li><li xss=removed>Write clean, reusable, and efficient code following best practices.</li><li xss=removed>Integrate third-party APIs and backend services.</li><li xss=removed>Test, troubleshoot, and debug mobile applications to ensure optimal performance.</li><li xss=removed>Stay updated with the latest trends in mobile app development and suggest improvements.</li></ul><h3 xss=removed><span xss=removed>Required Skills:</span></h3><ul xss=removed><li xss=removed>Strong knowledge of Flutter and Dart programming language.</li><li xss=removed>Experience in developing and deploying mobile apps for both Android and iOS.</li><li xss=removed>Familiarity with RESTful APIs and integration of third-party services.</li><li xss=removed>Experience with state management solutions like Provider, Bloc, or Riverpod.</li><li xss=removed>Knowledge of mobile app architecture patterns like MVVM, MVC, or MVP.</li><li xss=removed>Strong problem-solving skills and attention to detail.</li><li xss=removed>Understanding of version control systems (Git).</li><li xss=removed>Good communication skills and ability to work in a team.</li></ul><h3 xss=removed><span xss=removed>Additional Skills (Optional):</span></h3><ul xss=removed><li xss=removed>Experience with Firebase or other backend-as-a-service platforms.</li><li xss=removed>Familiarity with native Android (Java/Kotlin) or iOS (Swift) development.</li><li xss=removed>Knowledge of app deployment and submission process on Google Play Store and Apple App Store.</li></ul><h3 xss=removed><span xss=removed>Benefits:</span></h3><ul xss=removed><li xss=removed>Competitive salary.</li><li xss=removed>Collaborative and dynamic work environment.</li><li xss=removed>Opportunities for career growth and professional development.</li><li xss=removed>Health insurance and other benefits.</li></ul><h3 xss=removed><br xss=removed></h3>', 'published', '2024-09-30 06:03:59', 'all'),
(7, 'Front End Web Designer', 0, '3', '2024-09-30', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-30', '<p xss=removed><span xss=removed>TIC Limited</span>┬áis looking for a talented┬á<span xss=removed>Front End Web Designer</span>┬áto join our team. We are a leading technology company in Bangladesh, and we are expanding our team to meet the growing demands of our clients. This is a full-time office-based position (no remote work) located at our Dhaka office.</p><h3 xss=removed><span xss=removed>Job Responsibilities:</span></h3><ul xss=removed><li xss=removed>Design and implement intuitive, user-friendly interfaces for websites and web applications.</li><li xss=removed>Collaborate with back-end developers and graphic designers to improve usability.</li><li xss=removed>Ensure high-quality graphic standards and brand consistency.</li><li xss=removed>Optimize web pages for maximum speed and scalability.</li><li xss=removed>Create and maintain design wireframes, mockups, and other UI/UX assets.</li><li xss=removed>Work closely with the marketing and content teams to align designs with company goals and customer expectations.</li></ul><h3 xss=removed><span xss=removed>Requirements:</span></h3><ul xss=removed><li xss=removed>BachelorÔÇÖs degree in Computer Science, IT, or related field (or equivalent work experience).</li><li xss=removed>Proven work experience as a Front End Web Designer or in a similar role.</li><li xss=removed>Proficiency in HTML5, CSS3, JavaScript, and jQuery.</li><li xss=removed>Hands-on experience with front-end frameworks (such as Bootstrap, Tailwind).</li><li xss=removed>Experience with design tools like Figma, Adobe XD, or Sketch.</li><li xss=removed>Strong understanding of responsive web design principles.</li><li xss=removed>Knowledge of SEO best practices.</li><li xss=removed>Excellent problem-solving skills and attention to detail.</li><li xss=removed>Ability to work effectively in a team and meet project deadlines.</li></ul><h3 xss=removed><span xss=removed>Additional Skills (Optional):</span></h3><ul xss=removed><li xss=removed>Experience with CMS platforms like WordPress or Joomla.</li><li xss=removed>Familiarity with version control tools (Git).</li><li xss=removed>Knowledge of UI/UX best practices.</li></ul><h3 xss=removed><span xss=removed>Benefits:</span></h3><ul xss=removed><li xss=removed>Competitive salary.</li><li xss=removed>Friendly and dynamic work environment.</li><li xss=removed>Opportunities for professional development and career growth.</li><li xss=removed>Health insurance and other benefits.</li></ul><h3 xss=removed><span xss=removed>How to Apply:</span></h3><p xss=removed>Interested candidates are requested to send their updated CV along with a portfolio of previous work to┬á<span xss=removed>hr@tic.com.bd</span>┬áor apply jobs from our website. Please include \"Front End Web Designer Application\" in the subject line.</p>', 'published', '2024-09-30 06:05:39', 'all'),
(8, 'UI UX Designer ', 3, '2', '2024-09-30', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-30', '<p xss=removed><span xss=removed>Company Overview</span></p><p xss=removed>TIC Limited is a leading provider of innovative digital solutions, offering a range of services including domain hosting, data solutions, and digital marketing. As we continue to grow, we are looking for a talented┬á<span xss=removed>UI/UX Designer</span>┬áto join our dynamic team.</p><h3 xss=removed><br xss=removed></h3><p xss=removed><span xss=removed>Key Responsibilities</span>:</p><ul xss=removed><li xss=removed>Design and develop intuitive and engaging user interfaces for web and mobile applications.</li><li xss=removed>Collaborate with cross-functional teams, including developers and product managers, to create seamless user experiences.</li><li xss=removed>Conduct user research, create wireframes, prototypes, and visual designs based on user needs and business goals.</li><li xss=removed>Test and evaluate user experiences to ensure product quality and consistency.</li><li xss=removed>Stay updated on the latest UI/UX design trends and tools, applying them to projects where relevant.</li></ul><p xss=removed><span xss=removed>Requirements</span>:</p><ul xss=removed><li xss=removed>Proven experience as a UI/UX Designer, with a strong portfolio showcasing web and mobile design work.</li><li xss=removed>Proficiency in design software such as Adobe XD, Figma, Sketch, or similar tools.</li><li xss=removed>Strong understanding of user-centered design principles and best practices.</li><li xss=removed>Ability to create wireframes, storyboards, user flows, and prototypes.</li><li xss=removed>Excellent communication skills, with the ability to clearly present design ideas and concepts.</li></ul><p xss=removed><span xss=removed>Bonus Skills</span>:</p><ul xss=removed><li xss=removed>Familiarity with front-end technologies like HTML, CSS, and JavaScript.</li><li xss=removed>Experience with design systems and responsive design.</li></ul><p xss=removed><span xss=removed>Educational Qualification</span>:</p><ul xss=removed><li xss=removed>Bachelor\'s degree in Graphic Design, Interaction Design, Computer Science, or a related field.</li></ul>', 'published', '2024-09-30 06:14:00', 'all'),
(9, 'Graphic Designer', 3, '2', '2024-10-07', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-09', '<p><strong>Job Description:</strong><br>TIC Limited is looking for a skilled <strong>Graphic Designer</strong> to join our team in Rajshahi! If you have a passion for visual creativity and are looking to expand your career in a dynamic and innovative environment, this role is perfect for you. As a Graphic Designer at TIC Limited, you will collaborate with our marketing and content teams to design compelling visuals for both digital and print media.</p><p><strong>Key Responsibilities:</strong></p><ul><li>Design and produce visual assets for digital platforms, including social media posts, web banners, ads, and email templates.</li><li>Create print materials such as brochures, flyers, and posters for campaigns and events.</li><li>Work closely with the marketing team to develop innovative and creative design solutions.</li><li>Ensure brand consistency across all design projects.</li><li>Manage multiple design projects with varying deadlines.</li><li>Stay current with design trends and software advancements to continuously improve design output.</li></ul><p><strong>Qualifications:</strong></p><ul><li>2-4 years of experience as a Graphic Designer or in a related creative role.</li><li>Proficiency in Adobe Creative Suite (Photoshop, Illustrator, InDesign) or other graphic design software.</li><li>A strong portfolio showcasing creative projects in various formats (digital, print).</li><li>Excellent knowledge of typography, layout, color theory, and visual design principles.</li><li>Ability to meet deadlines and manage multiple projects.</li><li>Strong communication skills and attention to detail.</li></ul><p><strong>Bonus Skills (Optional):</strong></p><ul><li>Experience with video editing or motion graphics (e.g., Adobe After Effects).</li><li>Knowledge of UI/UX design principles.</li><li>Familiarity with web design tools such as Figma or Sketch.</li></ul><p><strong>Why Join TIC Limited:</strong></p><ul><li>Work in a fast-growing, innovative company.</li><li>Competitive salary and benefits.</li><li>Opportunities for professional development and career growth.</li><li>Collaborative and creative work environment.</li></ul>', 'published', '2024-10-07 06:20:34', 'all'),
(10, 'Receptionist', 43, '1', '2024-10-07', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-10', '<p><strong>Job Description:</strong><br>TIC Limited is seeking a friendly, organized, and professional <strong>Receptionist</strong> to be the face of our office in Rajshahi. As a Receptionist, you will play a crucial role in creating a welcoming atmosphere for visitors, managing front desk operations, and providing administrative support to various departments.</p><p><strong>Key Responsibilities:</strong></p><ul><li>Greet and welcome visitors with a warm, friendly demeanor.</li><li>Answer and direct phone calls to appropriate personnel.</li><li>Handle incoming and outgoing mail and deliveries.</li><li>Assist with scheduling meetings and managing conference rooms.</li><li>Provide basic administrative support, including data entry, filing, and document preparation.</li><li>Maintain office supplies inventory and order items as needed.</li><li>Assist in managing company records and ensuring they are up to date.</li><li>Maintain the cleanliness and orderliness of the reception area.</li></ul><p><strong>Qualifications:</strong></p><ul><li>Proven work experience as a Receptionist, Front Office Representative, or similar role.</li><li>Proficiency in Microsoft Office Suite (Word, Excel, PowerPoint) or equivalent tools.</li><li>Excellent communication and interpersonal skills.</li><li>Ability to handle multi-line phone systems professionally.</li><li>Strong organizational skills and attention to detail.</li><li>Ability to work in a fast-paced environment and manage multiple tasks.</li><li>Fluent in both Bengali and English (written and spoken).</li></ul><p><strong>Why Join TIC Limited:</strong></p><ul><li>Work in a dynamic and growing company.</li><li>Opportunities for professional growth and development.</li><li>Supportive and team-oriented work environment.</li><li>Competitive salary and benefits package.</li></ul>', 'published', '2024-10-07 06:23:03', 'all'),
(11, 'Phone Call Representative', 33, '4', '2024-10-07', 'full_time', '1-2 years of experience', '18-30', 'Negotiable based on experience and skills', '2024-10-12', '<p><strong>Job Description:</strong><br>TIC Limited is looking for an enthusiastic and customer-focused <strong>Phone Call Representative</strong> to join our team in Rajshahi. In this role, you will be the first point of contact for our customers, addressing inquiries, providing information, and ensuring a positive customer experience over the phone. If you have strong communication skills and a passion for helping people, this role is perfect for you!</p><p><strong>Key Responsibilities:</strong></p><ul><li>Answer inbound customer calls in a friendly and professional manner.</li><li>Provide accurate information regarding TIC LimitedÔÇÖs products and services.</li><li>Resolve customer inquiries, issues, and complaints in a timely and efficient manner.</li><li>Record and maintain customer information and interactions in the companyÔÇÖs CRM system.</li><li>Identify customer needs and provide appropriate solutions or escalate issues to the appropriate department.</li><li>Follow up with customers to ensure satisfaction with solutions provided.</li><li>Meet or exceed daily call volume and performance targets.</li><li>Assist with outbound calls for customer surveys or feedback when necessary.</li></ul><p><strong>Qualifications:</strong></p><ul><li>Proven experience as a Phone Call Representative, Customer Service Representative, or similar role.</li><li>Strong verbal communication skills in both Bengali and English.</li><li>Excellent listening and problem-solving skills.</li><li>Proficiency in using computer systems, including Microsoft Office and CRM software.</li><li>Ability to work under pressure and handle a high volume of calls.</li><li>Strong attention to detail and ability to document customer interactions accurately.</li></ul><p><strong>Why Join TIC Limited:</strong></p><ul><li>Competitive salary and benefits package.</li><li>Opportunities for career growth and development.</li><li>Friendly and collaborative work environment.</li><li>Ongoing training and support to help you succeed.</li></ul>', 'published', '2024-10-07 06:29:06', 'all'),
