INSERT INTO `tbl_outgoing_emails` (`id`, `sent_to`, `sent_from`, `subject`, `message`, `date_sent`, `delivered`) VALUES
(1, 'moktadir@tic.com.bd', 'support@tic.com.bd TIC Limited', '[ TIC Limited ] Activate Account', '<p>Welcome to TIC Limited!</p>\r\n\r\n<p>Thanks for joining TIC Limited. We listed your sign in details below, make sure you keep them safe.</p>\r\n\r\n<p>To verify your email address, please follow this link:<br />\r\n<big><strong><a href=\"https://cp.tic.com.bd/login/activate/2/646cd71ee0110b8f51f203b3a3aeeb23\">Finish your registration...</a></strong></big><br />\r\nLink doesn&#39;t work? Copy the following link to your browser address bar:<br />\r\n<a href=\"https://cp.tic.com.bd/login/activate/2/646cd71ee0110b8f51f203b3a3aeeb23\">https://cp.tic.com.bd/login/activate/2/646cd71ee0110b8f51f203b3a3aeeb23</a></p>\r\n\r\n<p><br />\r\n<br />\r\nPlease verify your email within 48 hours, otherwise your registration will become invalid and you will have to register again.<br />\r\n<br />\r\n<br />\r\nYour username: moktadir<br />\r\nYour email address: moktadir@tic.com.bd<br />\r\nYour password: 123456<br />\r\n<br />\r\nHave fun!<br />\r\nThe TIC Limited Team</p>\r\n', '2024-09-28 11:06:18', 0),
(2, 'gsmforid@gmail.com', 'info@tic.com.bd TIC Limited', '111', '<section class=\"content\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            <div class=\"panel panel-custom\">\n                <div class=\"panel-heading\">\n                    111                </div>\n                <div class=\"mailbox-read-message text-justify margin\">\n                    <p>1111</p>\n                </div><!-- /.mailbox-read-message -->\n            </div><!-- /.box-body -->\n        </div><!-- /. box -->\n    </div><!-- /.col -->\n    </div>\n</section>', '2024-09-28 12:42:36', 0),
(3, 'gsmforid@gmail.com', 'info@tic.com.bd TIC Limited', 'hi there?', '<section class=\"content\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            <div class=\"panel panel-custom\">\n                <div class=\"panel-heading\">\n                    hi there?                </div>\n                <div class=\"mailbox-read-message text-justify margin\">\n                    <p>fsfsfsf</p>\n                </div><!-- /.mailbox-read-message -->\n            </div><!-- /.box-body -->\n        </div><!-- /. box -->\n    </div><!-- /.col -->\n    </div>\n</section>', '2024-09-28 15:38:34', 0),
(4, NULL, 'hello@tic.com.bd TIC Limited', '[ TIC Limited ] Payment Received', '<div style=\"height: 7px; background-color: #535353;\"></div>\n<div style=\"background-color:#E8E8E8; margin:0px; padding:55px 20px 40px 20px; font-family:Open Sans, Helvetica, sans-serif; font-size:12px; color:#535353;\"><div style=\"text-align:center; font-size:24px; font-weight:bold; color:#535353;\">Payment Received</div>\n<div style=\"border-radius: 5px 5px 5px 5px; padding:20px; margin-top:45px; background-color:#FFFFFF; font-family:Open Sans, Helvetica, sans-serif; font-size:13px;\"><p>Dear Customer</p>\n<p>We have received your payment of BAN 15000. </p>\n<p>Thank you for your Payment and business. We look forward to working with you again.</p>\n--------------------------<br>Regards<br>The TIC Limited Team</div>\n</div>', '2024-09-28 19:11:15', 0),
